    merge_comm(c, PHIL_CONTEXT_FILL_CH2)
    merge_comm(c, PHIL_CONTEXT_FILL_CH3)
    save_comm('mkt-context', 'philippians', c)
    print(f'Phil context: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

